import React from 'react';
import { Reveal } from './Reveal';
import { ClipboardList, Zap, Send, LineChart } from 'lucide-react';

const steps = [
  {
    title: "Intake",
    description: "Standardize how work enters your firm. No more scattered emails or missing context.",
    icon: ClipboardList,
    color: "bg-blue-50"
  },
  {
    title: "Automate",
    description: "Bespoke AI agents handle the repetitive drafting and research with elite precision.",
    icon: Zap,
    color: "bg-amber-50"
  },
  {
    title: "Submit",
    description: "Deliver high-quality work hours or days before the deadline. Speed as a competitive advantage.",
    icon: Send,
    color: "bg-green-50"
  },
  {
    title: "Track",
    description: "Real-time visibility into every request, status, and billable milestone.",
    icon: LineChart,
    color: "bg-purple-50"
  }
];

export const Process: React.FC = () => {
  return (
    <section id="process" className="py-40 bg-white text-makini-navy relative">
      <div className="max-w-7xl mx-auto px-6 md:px-12 relative z-10">
        <div className="text-center mb-24">
          <Reveal width="100%">
            <span className="text-makini-royal uppercase tracking-[0.2em] text-xs font-bold mb-4 block">The Workflow</span>
          </Reveal>
          <Reveal width="100%" delay={0.1}>
            <h2 className="font-serif text-4xl md:text-6xl text-makini-navy">
              From Request to <span className="italic text-makini-royal">Resolution</span>
            </h2>
          </Reveal>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-12">
          {steps.map((step, index) => (
            <Reveal key={index} delay={index * 0.1} width="100%">
              <div className="relative flex flex-col items-center text-center group">
                {/* Connector Line for desktop */}
                {index < steps.length - 1 && (
                  <div className="hidden lg:block absolute top-12 left-[calc(50%+40px)] w-[calc(100%-80px)] h-px bg-makini-soft/20 z-0"></div>
                )}

                <div className={`w-24 h-24 ${step.color} rounded-full flex items-center justify-center mb-8 relative z-10 border border-makini-soft/10 group-hover:scale-110 transition-transform duration-500 shadow-sm`}>
                  <step.icon className="w-10 h-10 text-makini-royal" strokeWidth={1.5} />
                  <div className="absolute -top-2 -right-2 w-8 h-8 bg-makini-navy text-white rounded-full flex items-center justify-center text-xs font-bold border-2 border-white">
                    0{index + 1}
                  </div>
                </div>

                <h3 className="font-serif text-2xl mb-4 text-makini-navy group-hover:text-makini-royal transition-colors">
                  {step.title}
                </h3>
                <p className="text-makini-navy/60 leading-relaxed text-sm max-w-[200px]">
                  {step.description}
                </p>
              </div>
            </Reveal>
          ))}
        </div>

        <Reveal width="100%" delay={0.5}>
          <div className="mt-24 p-12 bg-makini-ice/50 rounded-sm border border-makini-soft/10 text-center max-w-3xl mx-auto">
            <h4 className="font-serif text-2xl mb-4 italic text-makini-royal">"It makes them submit work faster than ever."</h4>
            <p className="text-makini-navy/70 text-sm tracking-wide">
              Our core objective is to reduce the friction between instruction and delivery. 
              Makini AI doesn't just assist; it accelerates.
            </p>
          </div>
        </Reveal>
      </div>
    </section>
  );
};

import React, { useState } from 'react';
import { Menu, X, Mail } from 'lucide-react';
import { MakiniLogo } from './MakiniLogo';

export const Navbar: React.FC = () => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Navbar is always white to accommodate the logo, per specific design requirements
  const navClasses = "fixed w-full z-50 bg-white border-b border-makini-navy/5 py-2 shadow-sm transition-all duration-300";

  const navItems = ['Expertise', 'Process', 'Integration', 'Impact', 'Contact'];

  return (
    <nav className={navClasses}>
      <div className="max-w-7xl mx-auto px-6 md:px-12 flex justify-between items-center">
        {/* Logo Container */}
        <a 
          href="#hero"
          className="cursor-pointer z-50 block"
          onClick={() => setIsMobileMenuOpen(false)}
        >
          <div className="h-8 w-auto flex items-center">
            <MakiniLogo className="h-full w-auto" />
          </div>
        </a>

        {/* Desktop Menu */}
        <div className="hidden md:flex items-center space-x-10">
          {navItems.map((item) => (
            <a
              key={item}
              href={`#${item.toLowerCase()}`}
              className="text-xs uppercase tracking-[0.15em] font-bold text-makini-navy hover:text-makini-royal transition-colors duration-300"
            >
              {item}
            </a>
          ))}

          <a 
            href="mailto:info@makini.tech"
            className="bg-makini-royal text-white border border-transparent px-8 py-3 text-xs uppercase tracking-[0.15em] font-bold hover:bg-makini-navy hover:shadow-lg hover:-translate-y-0.5 transition-all duration-300 ease-out rounded-sm"
          >
            Inquire
          </a>
        </div>

        {/* Mobile Toggle */}
        <div className="md:hidden z-50 flex items-center gap-4">
          <button 
            onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)} 
            type="button"
            className="text-makini-navy hover:text-makini-royal transition-colors p-2"
          >
            {isMobileMenuOpen ? <X size={24} strokeWidth={1.5} /> : <Menu size={24} strokeWidth={1.5} />}
          </button>
        </div>
      </div>

      {/* Mobile Menu Overlay */}
      <div className={`fixed inset-0 bg-white z-40 flex flex-col items-center justify-center space-y-10 transition-all duration-500 ${isMobileMenuOpen ? 'opacity-100 visible' : 'opacity-0 invisible pointer-events-none'}`}>
        {navItems.map((item) => (
          <a
            key={item}
            href={`#${item.toLowerCase()}`}
            onClick={() => setIsMobileMenuOpen(false)}
            className="text-3xl font-serif text-makini-navy hover:text-makini-royal transition-colors tracking-wide"
          >
            {item}
          </a>
        ))}
        <a 
            href="mailto:info@makini.tech"
            onClick={() => setIsMobileMenuOpen(false)}
            className="flex items-center gap-3 text-makini-royal text-lg mt-8 font-medium tracking-wide"
        >
          <Mail size={18} /> info@makini.tech
        </a>
      </div>
    </nav>
  );
};

import { Navbar } from './components/Navbar';
import { Hero } from './components/Hero';
import { Partners } from './components/Partners';
import { Services } from './components/Services';
import { Process } from './components/Process';
import { Integrations } from './components/Integrations';
import { Impact } from './components/Impact';
import { Contact } from './components/Contact';
import { Footer } from './components/Footer';

function App() {
  return (
    <div className="min-h-screen bg-makini-ice text-makini-navy font-sans selection:bg-makini-soft selection:text-white">
      <Navbar />
      <main>
        <Hero />
        <Partners />
        <Services />
        <Process />
        <Integrations />
        <Impact />
        <Contact />
      </main>
      <Footer />
    </div>
  );
}

export default App;
